/* ---------------------------------------------------------
   SHIELD STATUS GLYPH — élément signature
--------------------------------------------------------- */
function StatusShield({ status, size = 16 }) {
  const map = {
    "à venir": { Icon: Shield, color: C.muted },
    "en cours": { Icon: Shield, color: C.brassLt },
    "envoyé": { Icon: ShieldCheck, color: C.sentry },
    "en attente": { Icon: ShieldQuestion, color: C.muted },
    "RAS": { Icon: ShieldCheck, color: C.sentry },
    "anomalie": { Icon: ShieldAlert, color: C.rust },
    "terminée": { Icon: ShieldCheck, color: C.muted },
  };
  const cfg = map[status] || map["à venir"];
  const { Icon, color } = cfg;
  return <Icon size={size} color={color} strokeWidth={2} />;
}

function StatusLabel({ status }) {
  const colorMap = {
    "à venir": C.muted, "en cours": C.brassLt, "envoyé": C.sentry,
    "en attente": C.muted, "RAS": C.sentry, "anomalie": C.rust, "terminée": C.muted,
  };
  return (
    <span className="f-mono flex items-center gap-1.5 text-xs uppercase tracking-wide"
      style={{ color: colorMap[status] || C.muted }}>
      <StatusShield status={status} size={13} /> {status}
    </span>
  );
}

/* ---------------------------------------------------------
   COMPOSANTS PARTAGÉS
--------------------------------------------------------- */
function NotificationBell({ items, onOpen }) {
  const [open, setOpen] = useState(false);
  const unread = items.filter((n) => !n.read).length;
  return (
    <div className="relative">
      <button onClick={() => { const next = !open; setOpen(next); if (next) onOpen(); }}
        className="relative p-1.5 rounded-lg" style={{ color: C.muted }}>
        <Bell size={18} />
        {unread > 0 && (
          <span className="absolute -top-1 -right-1 f-mono text-[9px] rounded-full px-1.5 py-0.5" style={{ background: C.brass, color: C.ink }}>
            {unread}
          </span>
        )}
      </button>
      {open && (
        <div className="absolute right-0 mt-2 rounded-lg p-3 z-50" style={{ width: 260, background: C.inkRaised, border: `1px solid ${C.line}`, boxShadow: "0 8px 24px rgba(0,0,0,0.18)" }}>
          <div className="f-mono text-[10px] mb-2" style={{ color: C.muted }}>NOTIFICATIONS</div>
          <div className="flex flex-col gap-2.5 max-h-64 overflow-y-auto">
            {items.length === 0 && <div className="f-body text-xs" style={{ color: C.muted }}>Aucune notification.</div>}
            {items.slice().reverse().map((n) => (
              <div key={n.id}>
                <div className="f-body text-xs" style={{ color: C.parchment }}>{n.text}</div>
                <div className="f-mono text-[9px] mt-0.5" style={{ color: C.muted }}>{n.t}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

