/* Formulaire de rapport — utilisé pour une nouvelle rédaction ET pour une modification approuvée */
function ReportForm({ initial, onSubmit, onCancel }) {
  const [rStatut, setRStatut] = useState(initial?.statut || null);
  const [rDesc, setRDesc] = useState(initial?.description || "");
  const [rDebut, setRDebut] = useState(initial?.heureDebut || "");
  const [rFin, setRFin] = useState(initial?.heureFin || "");
  const [rPhotos, setRPhotos] = useState(0);

  return (
    <div>
      <button onClick={onCancel} className="flex items-center gap-1 mb-4 f-mono text-xs" style={{ color: C.brassLt }}>
        <ChevronLeft size={14} /> RETOUR
      </button>
      <div className="f-display text-lg mb-4" style={{ color: C.parchment }}>
        {initial ? "Modifier le rapport" : "Rapport d'intervention"}
      </div>

      <div className="flex flex-wrap gap-2 mb-5">
        {[`${AGENT.prenom} ${AGENT.nom}`, AGENT.matricule, "date auto. à la validation"].map((t, i) => (
          <span key={i} className="f-mono text-[10px] px-2 py-1 rounded" style={{ background: C.inkRaised2, color: C.muted, border: `1px solid ${C.line}` }}>{t}</span>
        ))}
      </div>

      <div className="f-mono text-[11px] mb-2" style={{ color: C.muted }}>STATUT</div>
      <div className="flex gap-2 mb-4">
        <button onClick={() => setRStatut("RAS")} className="flex-1 py-2.5 rounded-lg f-body text-sm flex items-center justify-center gap-2"
          style={{ background: rStatut === "RAS" ? C.sentry : C.inkRaised, color: rStatut === "RAS" ? C.ink : C.parchment, border: `1px solid ${rStatut === "RAS" ? C.sentry : C.line}` }}>
          <ShieldCheck size={15} /> RAS
        </button>
        <button onClick={() => setRStatut("anomalie")} className="flex-1 py-2.5 rounded-lg f-body text-sm flex items-center justify-center gap-2"
          style={{ background: rStatut === "anomalie" ? C.rust : C.inkRaised, color: rStatut === "anomalie" ? C.ink : C.parchment, border: `1px solid ${rStatut === "anomalie" ? C.rust : C.line}` }}>
          <ShieldAlert size={15} /> Anomalie
        </button>
      </div>

      {rStatut === "anomalie" && (
        <div className="mb-4">
          <div className="f-mono text-[11px] mb-2" style={{ color: C.muted }}>DESCRIPTION DE L'ANOMALIE</div>
          <textarea value={rDesc} onChange={(e) => setRDesc(e.target.value)} rows={3}
            placeholder="Décrire ce qui a été constaté..."
            className="w-full rounded-lg p-3 f-body text-sm resize-none focus:outline-none"
            style={{ background: C.inkRaised, color: C.parchment, border: `1px solid ${C.rust}` }} />
        </div>
      )}

      <div className="flex gap-3 mb-4">
        <Field label="Heure de début (facultatif)" type="time" value={rDebut} onChange={(e) => setRDebut(e.target.value)} />
        <Field label="Heure de fin (facultatif)" type="time" value={rFin} onChange={(e) => setRFin(e.target.value)} />
      </div>

      <div className="mb-6">
        <div className="f-mono text-[11px] mb-2" style={{ color: C.muted }}>PHOTOS (FACULTATIF)</div>
        <button onClick={() => setRPhotos((n) => n + 1)}
          className="w-full py-4 rounded-lg flex flex-col items-center gap-1.5"
          style={{ background: C.inkRaised, border: `1px dashed ${C.line}` }}>
          <Camera size={18} color={C.muted} />
          <span className="f-mono text-[10px]" style={{ color: C.muted }}>
            {rPhotos > 0 ? `${rPhotos} photo(s) ajoutée(s)` : "Ajouter des photos"}
          </span>
        </button>
      </div>

      <button disabled={!rStatut}
        onClick={() => onSubmit({ statut: rStatut, description: rStatut === "anomalie" ? rDesc : "", heureDebut: rDebut, heureFin: rFin })}
        className="w-full py-3 rounded-lg f-display text-sm tracking-wide flex items-center justify-center gap-2"
        style={{ background: rStatut ? C.brass : C.line, color: rStatut ? C.ink : C.muted }}>
        <Check size={16} /> VALIDER LE RAPPORT
      </button>
    </div>
  );
}

