function AgentWebApp({ missions, setMissions, payslips, news, notifications, notify, markRead, addIssue }) {
  const [view, setView] = useState("accueil"); // accueil | missions | planning | fiches | messages
  const [missionsView, setMissionsView] = useState("actives");
  const [selectedId, setSelectedId] = useState(null);
  const [collapsed, setCollapsed] = useState(false);
  const [showReportForm, setShowReportForm] = useState(false);
  const [showProfile, setShowProfile] = useState(false);
  const [showIssue, setShowIssue] = useState(false);

  const myMissions = missions.filter((m) => m.agents.includes(AGENT.nom));
  const selected = myMissions.find((m) => m.id === selectedId) || null;
  const list = myMissions.filter((m) => missionsView === "actives" ? !m.rapports[AGENT.nom] : !!m.rapports[AGENT.nom]);
  const rapport = selected ? selected.rapports[AGENT.nom] : null;
  const reportInitial = rapport && rapport.locked === false ? rapport : null;

  function openMission(m) { setSelectedId(m.id); setShowReportForm(false); }

  function updateRapport(missionId, patch) {
    setMissions((prev) => prev.map((m) =>
      m.id === missionId
        ? { ...m, rapports: { ...m.rapports, [AGENT.nom]: { ...(m.rapports[AGENT.nom] || {}), ...patch } } }
        : m
    ));
  }

  function submitReport(data) {
    updateRapport(selected.id, { ...data, locked: true, modifRequest: null });
    notify("admin", `Nouveau rapport de ${AGENT.prenom} ${AGENT.nom} — ${selected.lieu}`);
    setShowReportForm(false);
  }

  function requestModif(reason) {
    updateRapport(selected.id, { modifRequest: { raison: reason, etat: "en attente" } });
    notify("admin", `Demande de modification de ${AGENT.prenom} ${AGENT.nom} — ${selected.lieu}`);
  }

  return (
    <div className="rounded-xl overflow-hidden flex" style={{ height: 720, background: C.ink, border: `1px solid ${C.line}` }}>
      <div className="flex flex-col justify-between p-5 transition-all duration-200" style={{ width: collapsed ? 72 : 220, background: C.inkRaised, borderRight: `1px solid ${C.line}` }}>
        <div>
          <div className="flex items-center justify-between mb-2" style={{ minHeight: 26 }}>
            {!collapsed && <img src={LOGO_BLANC} alt="Praetorian Swiss Security" style={{ height: 26 }} />}
            <button onClick={() => setCollapsed((c) => !c)} className="p-1 rounded" style={{ color: C.muted, marginLeft: collapsed ? 0 : "auto" }}>
              <Menu size={18} />
            </button>
          </div>
          {!collapsed && (
            <div className="flex items-center justify-between mb-8">
              <span className="f-mono text-[10px]" style={{ color: C.muted }}>ESPACE AGENT</span>
              <div className="flex items-center gap-1.5">
                <button onClick={() => setShowIssue(true)} title="Signaler un problème" className="p-1 rounded" style={{ color: C.muted }}>
                  <AlertTriangle size={15} />
                </button>
                <NotificationBell items={notifications} onOpen={() => markRead("agent")} />
              </div>
            </div>
          )}
          {collapsed && <div className="mb-6" />}
          <div className="flex flex-col gap-1">
            {[
              { k: "accueil", label: "Accueil", Icon: LayoutDashboard },
              { k: "missions", label: "Missions", Icon: ClipboardList },
              { k: "planning", label: "Planning", Icon: CalendarDays },
              { k: "fiches", label: "Fiches de salaire", Icon: FileText },
              { k: "messages", label: "Messages", Icon: MessageCircle },
            ].map(({ k, label, Icon }) => (
              <button key={k} onClick={() => setView(k)} title={label}
                className={`flex items-center gap-2.5 px-3 py-2.5 rounded-lg f-body text-sm text-left ${collapsed ? "justify-center" : ""}`}
                style={{ background: view === k ? C.inkRaised2 : "transparent", color: view === k ? C.brassLt : C.muted }}>
                <Icon size={16} /> {!collapsed && label}
              </button>
            ))}
          </div>
        </div>
        {!collapsed && (
          <button onClick={() => setShowProfile(true)} className="text-left">
            <div className="f-body text-xs" style={{ color: C.parchment }}>{AGENT.prenom} {AGENT.nom}</div>
            <div className="f-mono text-[10px]" style={{ color: C.muted }}>{AGENT.matricule}</div>
          </button>
        )}
      </div>

      {showProfile && <ProfileModal onClose={() => setShowProfile(false)} />}
      {showIssue && <ReportIssueModal onClose={() => setShowIssue(false)} onSubmit={(text) => addIssue(`${AGENT.prenom} ${AGENT.nom} (agent)`, text)} />}

      <div className="flex-1 overflow-y-auto">
        {view === "accueil" && (
          <div className="p-6 max-w-2xl">
            <AgentHome missions={myMissions.filter((m) => !m.rapports[AGENT.nom])} onOpen={(m) => { openMission(m); setView("missions"); }} news={news} />
          </div>
        )}

        {view === "planning" && <div className="p-6"><MonthlyPlanning missions={myMissions} /></div>}
        {view === "fiches" && <div className="p-6 max-w-xl"><PayslipsList agentName={AGENT.nom} payslips={payslips} /></div>}
        {view === "messages" && <div className="p-6" style={{ height: "100%" }}><AgentMessages missions={missions} layout="web" notify={notify} /></div>}

        {view === "missions" && (
          <div className="flex" style={{ height: 720 }}>
            <div className="p-5 overflow-y-auto" style={{ width: 320, borderRight: `1px solid ${C.line}` }}>
              <div className="flex gap-2 mb-4">
                {[{ k: "actives", label: "Actives" }, { k: "historique", label: "Historique" }].map(({ k, label }) => (
                  <button key={k} onClick={() => setMissionsView(k)}
                    className="flex-1 py-1.5 rounded-lg f-mono text-[10px] uppercase tracking-wide"
                    style={{
                      background: missionsView === k ? C.brass : C.inkRaised,
                      color: missionsView === k ? C.ink : C.muted,
                      border: `1px solid ${missionsView === k ? C.brass : C.line}`,
                    }}>
                    {label}
                  </button>
                ))}
              </div>
              <div className="flex flex-col gap-2">
                {list.map((m) => (
                  <button key={m.id} onClick={() => openMission(m)} className="text-left rounded-lg p-3"
                    style={{ background: selected?.id === m.id ? C.inkRaised2 : C.inkRaised, border: `1px solid ${selected?.id === m.id ? C.brass : C.line}` }}>
                    <div className="f-body text-sm font-medium mb-1" style={{ color: C.parchment }}>{m.lieu}</div>
                    <div className="flex items-center gap-2 f-mono text-[10px] mb-1.5" style={{ color: C.muted }}>
                      <Clock size={11} />{m.heure} · {m.date}
                    </div>
                    <StatusLabel status={m.statut} />
                  </button>
                ))}
                {list.length === 0 && (
                  <div className="f-body text-xs text-center py-6" style={{ color: C.muted }}>Aucune mission ici.</div>
                )}
              </div>
            </div>

            <div className="flex-1 p-6 overflow-y-auto">
              {!selected ? (
                <div className="h-full flex items-center justify-center f-body text-sm" style={{ color: C.muted }}>
                  Sélectionne une mission pour voir le détail.
                </div>
              ) : !showReportForm ? (
                <div className="max-w-md">
                  <div className="f-display text-xl mb-1" style={{ color: C.parchment }}>{selected.lieu}</div>
                  <StatusLabel status={selected.statut} />
                  <div className="mt-5 mb-4">
                    <MissionInfoBlock mission={selected} wide />
                  </div>
                  {selected.instructions && (
                    <div className="rounded-lg p-3 mb-4" style={{ background: C.inkRaised2, border: `1px dashed ${C.brass}` }}>
                      <div className="f-mono text-[10px] mb-1" style={{ color: C.brassLt }}>NOTE DE L'ADMINISTRATEUR</div>
                      <div className="f-body text-xs" style={{ color: C.parchment }}>{selected.instructions}</div>
                    </div>
                  )}
                  <ReportStatusPanel rapport={rapport} mission={selected} agentName={`${AGENT.prenom} ${AGENT.nom}`} matricule={AGENT.matricule}
                    onWriteReport={() => setShowReportForm(true)}
                    onEditReport={() => setShowReportForm(true)}
                    onRequestModif={requestModif} />
                </div>
              ) : (
                <div className="max-w-md">
                  <ReportForm initial={reportInitial} onSubmit={submitReport} onCancel={() => setShowReportForm(false)} />
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

/* ===========================================================
   ADMIN — WEB DASHBOARD
=========================================================== */
function AdminApp({ missions, setMissions, payslips, setPayslips, pending, setPending, setAccounts, notifications, notify, markRead, addIssue }) {
  const [view, setView] = useState("dashboard");
  const [showModal, setShowModal] = useState(false);
  const [addMissionDate, setAddMissionDate] = useState(null);
  const [editingMission, setEditingMission] = useState(null);
  const [showAccountRequestModal, setShowAccountRequestModal] = useState(false);
  const [collapsed, setCollapsed] = useState(false);
  const [confirmDeleteMission, setConfirmDeleteMission] = useState(null);
  const [missionsView, setMissionsView] = useState("actives"); // actives | historique
  const [search, setSearch] = useState("");
  const [showIssue, setShowIssue] = useState(false);

  const enCours = missions.filter((m) => m.statut === "en cours" || m.statut === "à venir");
  const historique = missions.filter((m) => m.statut === "terminée");
  const rapportsAttente = missions.reduce((acc, m) => acc + Object.values(m.rapports).filter((r) => !r).length, 0);
  const anomalies = missions.reduce((acc, m) => acc + Object.values(m.rapports).filter((r) => r?.statut === "anomalie").length, 0);
  const agentsTerrain = new Set(missions.filter((m) => m.statut === "en cours").flatMap((m) => m.agents)).size;

  const listSource = missionsView === "actives" ? enCours : historique;
  const filteredList = listSource.filter((m) =>
    !search.trim() || m.lieu.toLowerCase().includes(search.toLowerCase()) || m.agents.some((a) => a.toLowerCase().includes(search.toLowerCase()))
  );

  function saveNewMission(data) {
    setMissions((prev) => [...prev, { id: Date.now(), ...data }]);
    if (data.agents.includes(AGENT.nom)) notify("agent", `Nouvelle mission : ${data.lieu} (${data.date} — ${data.heure})`);
  }
  function saveEditedMission(data) {
    setMissions((prev) => prev.map((m) => m.id === editingMission.id ? { ...m, ...data } : m));
    if (data.agents.includes(AGENT.nom)) notify("agent", `Mission modifiée : ${data.lieu}`);
  }

  return (
    <div className="rounded-xl overflow-hidden flex" style={{ height: 720, background: C.ink, border: `1px solid ${C.line}` }}>
      <div className="flex flex-col justify-between p-5 transition-all duration-200" style={{ width: collapsed ? 72 : 220, background: C.inkRaised, borderRight: `1px solid ${C.line}` }}>
        <div>
          <div className="flex items-center justify-between mb-2" style={{ minHeight: 26 }}>
            {!collapsed && <img src={LOGO_BLANC} alt="Praetorian Swiss Security" style={{ height: 26 }} />}
            <button onClick={() => setCollapsed((c) => !c)} className="p-1 rounded" style={{ color: C.muted, marginLeft: collapsed ? 0 : "auto" }}>
              <Menu size={18} />
            </button>
          </div>
          {!collapsed && (
            <div className="flex items-center justify-between mb-8">
              <span className="f-mono text-[10px]" style={{ color: C.muted }}>QG · ADMINISTRATION</span>
              <div className="flex items-center gap-1.5">
                <button onClick={() => setShowIssue(true)} title="Signaler un problème" className="p-1 rounded" style={{ color: C.muted }}>
                  <AlertTriangle size={15} />
                </button>
                <NotificationBell items={notifications} onOpen={() => markRead("admin")} />
              </div>
            </div>
          )}
          {collapsed && <div className="mb-6" />}
          <div className="flex flex-col gap-1">
            {[
              { k: "dashboard", label: "Tableau de bord", Icon: LayoutDashboard },
              { k: "planning", label: "Planning", Icon: CalendarDays },
              { k: "heures", label: "Heures", Icon: Clock },
              { k: "reports", label: "Rapports", Icon: ClipboardList },
              { k: "inscriptions", label: "Inscriptions", Icon: UserPlus, badge: pending.length },
              { k: "payslips", label: "Fiches de salaire", Icon: FileText },
              { k: "messages", label: "Messages", Icon: MessageCircle },
            ].map(({ k, label, Icon, badge }) => (
              <button key={k} onClick={() => setView(k)} title={label}
                className={`flex items-center gap-2.5 px-3 py-2.5 rounded-lg f-body text-sm text-left relative ${collapsed ? "justify-center" : ""}`}
                style={{ background: view === k ? C.inkRaised2 : "transparent", color: view === k ? C.brassLt : C.muted }}>
                <Icon size={16} /> {!collapsed && label}
                {!!badge && (
                  <span className="f-mono text-[9px] rounded-full px-1.5 py-0.5" style={{ background: C.brass, color: C.ink, marginLeft: collapsed ? 0 : "auto", position: collapsed ? "absolute" : "static", top: collapsed ? 2 : "auto", right: collapsed ? 2 : "auto" }}>
                    {badge}
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>
        {!collapsed && <div className="f-mono text-[10px]" style={{ color: C.muted }}>{ADMIN.nom}</div>}
      </div>

      {showIssue && <ReportIssueModal onClose={() => setShowIssue(false)} onSubmit={(text) => addIssue(`${ADMIN.nom} (admin)`, text)} />}

      <div className="flex-1 p-6 overflow-y-auto">
        {view === "dashboard" && (
          <>
            <div className="flex items-center justify-between mb-6">
              <div className="f-display text-xl" style={{ color: C.parchment }}>Tableau de bord</div>
              <button onClick={() => setShowModal(true)}
                className="flex items-center gap-2 px-4 py-2 rounded-lg f-body text-sm"
                style={{ background: C.brass, color: C.ink }}>
                <Plus size={15} /> Nouvelle mission
              </button>
            </div>

            <div className="grid grid-cols-4 gap-4 mb-8">
              <StatCard label="Agents sur le terrain" value={agentsTerrain} accent={C.brassLt} />
              <StatCard label="Rapports en attente" value={rapportsAttente} accent={C.muted} />
              <StatCard label="Anomalies signalées" value={anomalies} accent={C.rust} />
              <StatCard label="Missions actives" value={enCours.length} accent={C.sentry} />
            </div>

            <div className="flex items-center justify-between mb-3">
              <div className="flex gap-2">
                {[{ k: "actives", label: "En cours" }, { k: "historique", label: "Historique" }].map(({ k, label }) => (
                  <button key={k} onClick={() => setMissionsView(k)}
                    className="py-1.5 px-3 rounded-lg f-mono text-[10px] uppercase tracking-wide"
                    style={{
                      background: missionsView === k ? C.brass : C.inkRaised,
                      color: missionsView === k ? C.ink : C.muted,
                      border: `1px solid ${missionsView === k ? C.brass : C.line}`,
                    }}>
                    {label}
                  </button>
                ))}
              </div>
              <input value={search} onChange={(e) => setSearch(e.target.value)} placeholder="Rechercher un lieu ou un agent..."
                className="rounded-lg px-3 py-1.5 f-body text-xs focus:outline-none" style={{ width: 240, background: C.inkRaised2, color: C.parchment, border: `1px solid ${C.line}` }} />
            </div>

            <div className="flex flex-col gap-3">
              {filteredList.map((m) => {
                const hasAnomalie = Object.values(m.rapports).some((r) => r?.statut === "anomalie");
                return (
                  <div key={m.id} className="rounded-lg p-4" style={{ background: C.inkRaised, border: `1px solid ${hasAnomalie ? C.rust : C.line}` }}>
                    <div className="flex items-center justify-between mb-2">
                      <div className="f-body text-sm font-medium" style={{ color: C.parchment }}>{m.lieu}</div>
                      <div className="flex items-center gap-3">
                        <StatusLabel status={m.statut} />
                        {missionsView === "actives" && (
                          <button onClick={() => setEditingMission(m)} title="Modifier la mission">
                            <FileText size={15} color={C.muted} />
                          </button>
                        )}
                        <button onClick={() => setConfirmDeleteMission(m)} title="Supprimer la mission">
                          <Trash2 size={15} color={C.muted} />
                        </button>
                      </div>
                    </div>
                    <div className="f-mono text-[11px] mb-3" style={{ color: C.muted }}>{m.date} · {m.heure} — {m.objectif}</div>
                    <div className="flex gap-4">
                      {m.agents.map((a) => (
                        <div key={a} className="flex items-center gap-1.5 f-mono text-[11px]" style={{ color: C.parchment }}>
                          {a} <StatusLabel status={m.rapports[a]?.statut || "en attente"} />
                        </div>
                      ))}
                    </div>
                  </div>
                );
              })}
              {filteredList.length === 0 && (
                <div className="f-body text-sm" style={{ color: C.muted }}>Aucune mission ici.</div>
              )}
            </div>
          </>
        )}

        {view === "planning" && <MonthlyPlanning missions={missions} onAddMission={(d) => { setAddMissionDate(d); setShowModal(true); }} />}
        {view === "heures" && <HoursSummary missions={missions} />}
        {view === "reports" && <AdminReports missions={missions} setMissions={setMissions} notify={notify} />}
        {view === "inscriptions" && (
          <PendingRegistrationsPanel pending={pending} setPending={setPending} setAccounts={setAccounts}
            showCreateButton onCreateClick={() => setShowAccountRequestModal(true)} />
        )}
        {view === "payslips" && <AdminPayslips payslips={payslips} setPayslips={setPayslips} />}
        {view === "messages" && <AdminMessages notify={notify} />}
      </div>

      {showModal && <MissionFormModal initialDate={addMissionDate} onClose={() => { setShowModal(false); setAddMissionDate(null); }} onSave={saveNewMission} />}
      {editingMission && <MissionFormModal initial={editingMission} onClose={() => setEditingMission(null)} onSave={saveEditedMission} />}
      {showAccountRequestModal && (
        <NewClassicAccountRequestModal onClose={() => setShowAccountRequestModal(false)} onAdd={(p) => setPending((prev) => [...prev, { id: Date.now(), ...p }])} />
      )}
      {confirmDeleteMission && (
        <ConfirmModal
          title="Supprimer la mission"
          message={`Supprimer définitivement la mission « ${confirmDeleteMission.lieu} » ? Cette action est irréversible.`}
          onCancel={() => setConfirmDeleteMission(null)}
          onConfirm={() => {
            setMissions((prev) => prev.filter((m) => m.id !== confirmDeleteMission.id));
            setConfirmDeleteMission(null);
          }}
        />
      )}
    </div>
  );
}

function HoursSummary({ missions }) {
  function toMinutes(hhmm) {
    const [h, m] = hhmm.split(":").map(Number);
    return h * 60 + m;
  }

  const rows = [];
  missions.forEach((m) => {
    m.agents.forEach((a) => {
      const r = m.rapports[a];
      if (r && r.heureDebut && r.heureFin) {
        let mins = toMinutes(r.heureFin) - toMinutes(r.heureDebut);
        if (mins < 0) mins += 24 * 60;
        rows.push({ agent: a, lieu: m.lieu, date: m.date, mins });
      }
    });
  });

  const totalsByAgent = rows.reduce((acc, r) => { acc[r.agent] = (acc[r.agent] || 0) + r.mins; return acc; }, {});

  function fmt(mins) { return `${Math.floor(mins / 60)}h${String(mins % 60).padStart(2, "0")}`; }

  return (
    <>
      <div className="f-display text-xl mb-6" style={{ color: C.parchment }}>Heures travaillées</div>
      <div className="grid grid-cols-2 gap-4 mb-8">
        {Object.entries(totalsByAgent).map(([agent, mins]) => (
          <StatCard key={agent} label={`Total ${agent}`} value={fmt(mins)} accent={C.brassLt} />
        ))}
        {Object.keys(totalsByAgent).length === 0 && (
          <div className="f-body text-sm col-span-2" style={{ color: C.muted }}>Aucune heure renseignée pour le moment.</div>
        )}
      </div>

      {rows.length > 0 && (
        <>
          <div className="f-display text-sm tracking-wide mb-3" style={{ color: C.muted }}>DÉTAIL PAR MISSION</div>
          <div className="flex flex-col gap-2">
            {rows.map((r, i) => (
              <div key={i} className="rounded-lg p-3 flex items-center justify-between" style={{ background: C.inkRaised, border: `1px solid ${C.line}` }}>
                <div>
                  <div className="f-body text-sm" style={{ color: C.parchment }}>{r.lieu} — {r.agent}</div>
                  <div className="f-mono text-[10px]" style={{ color: C.muted }}>{r.date}</div>
                </div>
                <div className="f-mono text-sm" style={{ color: C.parchment }}>{fmt(r.mins)}</div>
              </div>
            ))}
          </div>
        </>
      )}
    </>
  );
}

function StatCard({ label, value, accent }) {
  return (
    <div className="rounded-lg p-4" style={{ background: C.inkRaised, border: `1px solid ${C.line}` }}>
      <div className="f-display text-3xl mb-1" style={{ color: accent }}>{value}</div>
      <div className="f-mono text-[10px] uppercase" style={{ color: C.muted }}>{label}</div>
    </div>
  );
}

function MonthlyPlanning({ missions, onAddMission }) {
  const [selectedDay, setSelectedDay] = useState(null);
  const year = 2026, month = 6;
  const firstWeekday = (new Date(year, month, 1).getDay() + 6) % 7;
  const daysInMonth = new Date(year, month + 1, 0).getDate();
  const cells = [...Array(firstWeekday).fill(null), ...Array(daysInMonth).keys()].map((v) => (v === null ? null : v + 1));

  function dateStr(d) { return `${String(d).padStart(2, "0")}.07.2026`; }
  function missionsForDay(d) { return missions.filter((m) => m.date === dateStr(d)); }

  return (
    <>
      <div className="f-display text-xl mb-6" style={{ color: C.parchment }}>Planning — Juillet 2026</div>
      <div className="grid grid-cols-7 gap-2 mb-2">
        {["Lun", "Mar", "Mer", "Jeu", "Ven", "Sam", "Dim"].map((d) => (
          <div key={d} className="f-mono text-[10px] text-center" style={{ color: C.muted }}>{d}</div>
        ))}
      </div>
      <div className="grid grid-cols-7 gap-2">
        {cells.map((d, i) => {
          if (!d) return <div key={i} />;
          const dayMissions = missionsForDay(d);
          const isToday = dateStr(d) === TODAY;
          return (
            <button key={i} onClick={() => setSelectedDay(d)}
              className="rounded-lg p-2 text-left flex flex-col gap-1"
              style={{ minHeight: 74, background: C.inkRaised, border: `1px solid ${isToday ? C.brass : C.line}` }}>
              <span className="f-mono text-[10px]" style={{ color: isToday ? C.brassLt : C.muted }}>{d}</span>
              {dayMissions.slice(0, 2).map((m) => (
                <span key={m.id} className="f-mono text-[8px] px-1 py-0.5 rounded truncate" style={{ background: C.inkRaised2, color: C.parchment }}>
                  {m.lieu.split(",")[0]}
                </span>
              ))}
              {dayMissions.length > 2 && <span className="f-mono text-[8px]" style={{ color: C.muted }}>+{dayMissions.length - 2}</span>}
            </button>
          );
        })}
      </div>

      {selectedDay && (
        <Modal onClose={() => setSelectedDay(null)} title={`${selectedDay} juillet 2026`}>
          <div className="flex flex-col gap-2">
            {missionsForDay(selectedDay).length === 0 ? (
              <div className="f-body text-sm" style={{ color: C.muted }}>Aucune mission planifiée ce jour-là.</div>
            ) : (
              missionsForDay(selectedDay).map((m) => (
                <div key={m.id} className="rounded-lg p-3" style={{ background: C.inkRaised2, border: `1px solid ${C.line}` }}>
                  <div className="flex items-center justify-between mb-1">
                    <div className="f-body text-sm" style={{ color: C.parchment }}>{m.lieu}</div>
                    <StatusLabel status={m.statut} />
                  </div>
                  <div className="f-mono text-[10px]" style={{ color: C.muted }}>{m.heure} — {m.agents.join(", ")}</div>
                </div>
              ))
            )}
            {onAddMission && (
              <button onClick={() => { onAddMission(dateStr(selectedDay)); setSelectedDay(null); }}
                className="w-full mt-2 py-2.5 rounded-lg f-display text-sm tracking-wide flex items-center justify-center gap-2"
                style={{ background: C.brass, color: C.ink }}>
                <Plus size={15} /> Ajouter une mission
              </button>
            )}
          </div>
        </Modal>
      )}
    </>
  );
}

